                        </div>
                    </div>
                </div>
            </div>

            {/* --- OBSERVATORY OVERLAY --- */}
            <div className={`fullscreen-overlay ${overlays.observatory ? 'is-active' : ''}`}>
                <canvas id="stars-bg" ref={starsRef}></canvas>
