.claim-btn.claimed { background-color: var(--accent-teal); color: var(--bg-dark); }

/* --- LIBRARY STYLES --- */
.library-fullscreen { position: fixed; top: 0; left: 0; right: 0; bottom: 0; z-index: 50; opacity: 0; pointer-events: none; clip-path: inset(10% 0 65% 0); transition: opacity 0.4s ease-in-out, clip-path 0.4s ease-in-out; }
.library-fullscreen.is-expanded { opacity: 1; pointer-events: auto; clip-path: inset(0% 0% 0% 0%); }
.bookshelf-perspective { perspective: 1000px; }
.book-container { transform-style: preserve-3d; display: grid; grid-template-columns: repeat(3, 1fr); column-gap: 0.5rem; padding: 0 0.5rem; position: relative; z-index: 10; margin-bottom: -0.5rem; min-height: 20px; }
.book-group { display: flex; flex-direction: column; align-items: center; }
.book-immersive { transition: transform 0.4s cubic-bezier(0.19, 1, 0.22, 1), box-shadow 0.4s cubic-bezier(0.19, 1, 0.22, 1); width: 100%; aspect-ratio: 3 / 4.2; background-size: cover; border-radius: 2px; box-shadow: 5px 5px 20px rgba(0,0,0,0.5); position: relative; }

/* --- HERITAGE ARCHIVE (UNIVERSITIES) --- */
.book-immersive.is-heritage {
    background: linear-gradient(145deg, #1a1a1a, #0a0a0a) !important;
    border-radius: 4px 8px 8px 4px;
    border-left: 5px solid rgba(0,0,0,0.4);
    box-shadow: 5px 5px 20px rgba(0,0,0,0.5);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;
    padding: 1.2rem 0.5rem;
    overflow: hidden;
}

.tilet-border-sm {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 8px;
    background: repeating-linear-gradient(90deg, 
        #2d5a27 0, #2d5a27 10px,
        #d4af37 10px, #d4af37 20px,
        #b32a2a 20px, #b32a2a 30px
    );
    opacity: 0.6;
}
.tilet-border-sm.bottom { top: auto; bottom: 0; }

.heritage-emblem {
    width: 44px; height: 44px;
    border-radius: 50%;
    border: 1px solid #c5a059;
    display: flex; align-items: center; justify-content: center;
    color: #c5a059;
    font-size: 1.2rem;
    background: radial-gradient(circle, rgba(197, 160, 89, 0.1) 0%, transparent 70%);
    margin-bottom: 0.5rem;
    z-index: 2;
}

.heritage-content {
    text-align: center; z-index: 2;
}

.heritage-label {
    font-family: 'Newsreader', serif; font-style: italic;
    font-size: 0.55rem; color: #666; letter-spacing: 1px; text-transform: uppercase;
}

.heritage-title {
    font-family: 'Cinzel', serif; color: #c5a059;
    font-size: 0.55rem; letter-spacing: 1px; line-height: 1.3;
    margin-top: 2px; text-transform: uppercase;
}

/* --- NORMALIZED VOLUMETRIC BOOK STACK --- */
.book-immersive.is-stack {
    background: linear-gradient(145deg, #3d2b1f, #1a1410) !important;
    border: 1px solid rgba(255, 215, 0, 0.1);
    /* Uniform bottom shadow with regular books */
    box-shadow: 5px 5px 20px rgba(0,0,0,0.5);
    z-index: 5;
}

/* The underlying books in the stack */
.book-immersive.is-stack::before {
    content: '';
    position: absolute;
    inset: 0;
    background: inherit;
    border-radius: inherit;
    /* Multiple shadows to create the 'stack' look without moving the base container */
    box-shadow: 
        -2px -2px 0 0 #2a1f10, 
        -3px -3px 0 0 #eaddcf, 
        -5px -5px 0 0 #3d2b1f,
        -6px -6px 0 0 #eaddcf;
    z-index: -1;
    transition: transform 0.3s ease;
}

.exam-stack-content {
    position: absolute;
    inset: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 0.5rem;
    background: radial-gradient(circle at center, rgba(255, 215, 0, 0.05) 0%, transparent 80%);
}

.exam-stack-content .emblem {
    font-size: 1.2rem;
    color: var(--linkoin-gold);
    margin-bottom: 4px;
}

.exam-stack-content .stack-title {
    font-family: 'Cinzel', serif;
    font-size: 0.6rem;
    font-weight: 700;
    color: var(--linkoin-gold);
    letter-spacing: 1px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.8);
}

.book-group:hover .book-immersive.is-stack::before {
    transform: translate(-4px, -4px);
}

.book-group:hover .book-immersive.is-stack {
    transform: scale(1.02);
}
.book-group:hover .book-immersive { transform: translateZ(35px) rotateY(-5deg) scale(1.05); box-shadow: 10px 20px 30px rgba(0,0,0,0.6); }
.info-overlay { position: absolute; bottom: 0; left: 0; right: 0; background: linear-gradient(to top, rgba(0,0,0,0.9), transparent); padding: 1rem; color: white; opacity: 0; transform: translateY(10px); transition: all 0.4s cubic-bezier(0.19, 1, 0.22, 1); }
.book-group:hover .info-overlay { opacity: 1; transform: translateY(0); }
.info-overlay .title { font-family: 'Poppins', sans-serif; font-size: 1rem; font-weight: 700; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.progress-bar { height: 4px; background-color: rgba(255,255,255,0.3); border-radius: 2px; margin-top: 0.5rem; }
.progress { height: 100%; background-color: var(--accent-teal); border-radius: 2px; }
.vignette-bg { background-color: #3E2723; background-image: linear-gradient(rgba(0,0,0,0.2), rgba(0,0,0,0.2)), url('https://www.transparenttextures.com/patterns/wood-pattern.png'); position: relative; }
.vignette-bg::after { content: ''; position: absolute; top: 0; left: 0; right: 0; bottom: 0; box-shadow: inset 0 0 100px 30px rgba(0,0,0,0.5); pointer-events: none; }
.pt-4 { padding-top: 1.5rem; }
.shelf-wood { height: 1rem; background-color: #5C3D2E; margin: 0 0.25rem; border-radius: 0.125rem; box-shadow: 0 8px 16px 0 rgba(0, 0, 0, 0.5), inset 0 2px 4px 0 rgba(255, 255, 255, 0.1); position: relative; z-index: 20; }
.fullscreen-header { background-color: rgba(12,12,12,0.8); backdrop-filter: blur(4px); z-index: 30; flex-shrink: 0; }
.header-main-row { display: flex; align-items: center; justify-content: space-between; padding: 1rem 1rem 0.5rem; }
.header-title-wrapper { display: flex; align-items: center; gap: 4px; cursor: pointer; }
.header-title-wrapper h2 { font-family: 'Poppins', sans-serif; color: var(--text-primary-dark); font-size: 1.125rem; font-weight: 700; }
.header-title-wrapper .chevron-icon { font-size: 1.25rem; transition: transform 0.3s ease; }
.header-title-wrapper.expanded .chevron-icon { transform: rotate(180deg); }
.filter-pills-container.expanded { max-height: 100px; opacity: 1; padding: 0.5rem 1rem 1rem; }
.library-filters { padding: 0.5rem 1rem 1rem; }

/* --- BOTTOM NAVIGATION BAR --- */
.navigation-magic {
    flex-shrink: 0;
    z-index: 100;
    position: relative;
    background: var(--surface-dark);
    height: auto;
    min-height: var(--nav-height);
    /* Removed extra 20px padding, kept only small buffer + safe area */
    padding-bottom: calc(5px + env(safe-area-inset-bottom));
    border-radius: 10px 10px 0 0;
}

.navigation-magic nav {
    height: var(--nav-height);
    width: 100%;
    display: flex;
}
.navigation-magic nav { display: flex; width: 100%; position: relative; height: 100%; }
.navigation-magic li {
    position: relative;
    list-style: none;
    width: 20%; /* Force exact math match with indicator */
    flex: 0 0 20%;
    z-index: 2;
    height: 100%;
}
.navigation-magic a { position: relative; display: flex; justify-content: center; align-items: center; flex-direction: column; width: 100%; text-align: center; font-weight: 500; cursor: pointer; height: 100%; }
.navigation-magic .icon {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    height: 60px; /* Reduced from 75px */
    width: 100%;
    font-size: 1.1em;
    transition: 0.5s;
    color: var(--text-secondary-dark);
}
/* Adjusted jump height for slimmer bar */
.navigation-magic li.active .icon { transform: translateY(-28px); color: var(--accent-teal); }
.navigation-magic .text { position: absolute; color: var(--accent-teal); font-weight: bold; font-size: 0.75em; letter-spacing: 0.05em; transition: 0.5s; opacity: 0; transform: translateY(15px); }
.navigation-magic li.active .text { opacity: 1; transform: translateY(8px); }
.indicator {
    position: absolute;
    /* Re-calculated for 40px circle (half is 20px) */
    top: -20px;
    width: 20%;
    height: 40px;
    background: transparent;
    display: flex;
    justify-content: center;
    transition: transform 0.5s cubic-bezier(0.68, -0.55, 0.27, 1.55);
    z-index: 1;
}

.indicator::before {
    content: '';
    position: absolute;
    /* Scaled down circle */
    width: 40px;
    height: 40px;
    border-radius: 50%;
    border: 4px solid var(--bg-dark);
    box-shadow: 0px 5px 15px rgba(0,0,0,0.2), 0px 0px 0px 3px var(--accent-teal);
    box-sizing: border-box;
    background: transparent;
}

/* --- DESKTOP / PC ADAPTATION (FIXED) --- */
@media (min-width: 900px) {
    /* 1. LAYOUT & SIDEBAR Z-INDEX FIX */
    .app-container {
        flex-direction: row;
        max-width: none;
        overflow: hidden;
    }
    .navigation-magic {
        order: -1;
        width: 260px;
        height: 100%;
        background: rgba(12, 12, 12, 0.98);
        border-right: 1px solid var(--border-color);
        border-radius: 0;
        display: flex;
        flex-direction: column;
        padding-top: 2rem;
        overflow-y: auto;
        z-index: 500; /* High z-index to ensure clickability */
        position: relative;
    }
    .navigation-magic nav {
        flex-direction: column;
        height: auto;
        gap: 0.5rem;
        padding: 0 1rem;
    }
    .navigation-magic li {
        width: 100%;
        height: 55px;
        flex: 0 0 auto;
        cursor: pointer; /* Ensure pointer cursor */
    }
    .navigation-magic a {
        flex-direction: row;
        justify-content: flex-start;
        padding-left: 1.5rem;
        border-radius: 12px;
        pointer-events: none; /* Let parent li handle click or bubble correctly */
    }
    .navigation-magic li a { pointer-events: auto; } /* Re-enable on anchor */

    .navigation-magic .icon {
        transform: none !important;
        line-height: normal;
        margin-right: 1rem;
        font-size: 1.2rem;
    }
    .navigation-magic .text {
        position: static;
        transform: none !important;
        opacity: 1;
        font-size: 1rem;
    }
    .navigation-magic li.active a {
        background: rgba(66, 215, 184, 0.15);
    }
    .navigation-magic .indicator { display: none; }

    /* 2. MAIN CONTENT & SCROLL FIXES */
    .main-content {
        flex-grow: 1;
        height: 100%;
        overflow: hidden;
        display: flex;
        flex-direction: column;
        background: radial-gradient(circle at top right, #1e1e1e, #0c0c0c);
        z-index: 1;
    }
    .tab-content.active {
        display: flex;
        width: 100%;
        height: 100%;
        overflow-y: auto; /* Ensure content scrolls */
        scroll-behavior: smooth;
    }
    .page-content, .scrollable-content {
        height: auto;
        overflow: visible;
    }

    /* 3. HOME TAB GRID */
    #home-content .page-content {
        display: grid;
        grid-template-columns: repeat(12, 1fr);
        grid-template-rows: auto auto;
        gap: 2rem;
        max-width: 1400px;
        margin: 0 auto;
        width: 100%;
        padding-bottom: 4rem;
    }
    .hero-wrapper { max-width: 1400px; margin: 0 auto; width: 100%; padding: 2rem 2rem 0; }
    .welcome-hero { height: 260px; border-radius: 24px; }
    .priority-section { grid-column: span 8; margin: 0; }
    .priority-scroll-wrapper { overflow: visible; }
    .priority-track { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; padding: 0; }
    .priority-card { width: 100%; min-height: 160px; }
    .whats-next-section { grid-column: span 4; }
    .next-task-container { height: 100%; min-height: 160px; }

    /* 4. STUDY TAB & LIBRARY OVERLAY FIX */
    #study-content .study-hub-content {
        display: grid;
        grid-template-columns: repeat(12, 1fr);
        gap: 2rem;
        padding: 2rem;
        max-width: 1400px;
        margin: 0 auto;
        overflow: visible;
    }
    .study-header { flex-shrink: 0; padding: 1rem 2rem; max-width: 1400px; margin: 0 auto; width: 100%; }
    .library-preview-wrapper {
        grid-column: span 5;
        min-height: 400px;
        cursor: pointer;
        z-index: 10; /* Ensure it's clickable above backgrounds */
    }
    .library-preview-wrapper .vignette-bg { height: 100%; border-radius: 24px; }
    .study-section { display: contents; }
    .compact-trigger { grid-column: span 7; margin: 0; }
    .guidance-path { grid-column: span 7; margin-top: 1rem; }
    .observatory-widget { grid-column: span 5; margin-top: 2rem; }

    /* 5. CONNECT & PROFILE TABS */
    #connect-content .content-panel {
        overflow-y: auto;
        height: 100%;
        padding: 2rem;
    }
    #connect-content .interactive-header { max-width: 1200px; margin: 0 auto; width: 100%; }
    .messages-list { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; max-width: 1200px; margin: 0 auto; }

    #profile-content .scrollable-content { overflow-y: auto; height: 100%; }
    .profile-hero { height: 300px; display: flex; align-items: flex-end; padding-bottom: 2rem; }
    .portal-cards-container { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; max-width: 1200px; margin: 0 auto; padding: 0 2rem; }
    .settings-group { max-width: 1200px; margin: 2rem auto; padding: 0 2rem; padding-bottom: 4rem; }

    /* 6. OVERLAYS (MODALS) - ULTIMATE FIX */
    .fullscreen-overlay, .library-fullscreen, .pavilion-overlay {
        display: flex !important;
        align-items: center;
        justify-content: center;
        background-color: rgba(0, 0, 0, 0.85);
        clip-path: none !important;
        z-index: 9999 !important;
        position: fixed;
        inset: 0;
        opacity: 0;
        pointer-events: none;
        visibility: hidden; /* Failsafe: Completely ignore when hidden */
        transition: opacity 0.3s ease, visibility 0.3s ease;
    }
    .fullscreen-overlay.is-active, .library-fullscreen.is-expanded {
        opacity: 1;
        pointer-events: auto;
        visibility: visible;
    }
    .overlay-content, #library-fullscreen > div, .pavilion-overlay {
        width: 900px !important;
        height: 85vh !important;
        margin: auto;
        position: fixed !important;
        inset: 0 !important;
        background: var(--bg-dark);
        border-radius: 24px;
        border: 1px solid var(--border-color);
        box-shadow: 0 25px 50px rgba(0,0,0,0.5);
        overflow: hidden;
        display: flex;
        flex-direction: column;
    }
    #library-fullscreen > div { background: var(--bg-dark); }
    .overlay-header { flex-shrink: 0; }
    .overlay-inner-content { overflow-y: auto; }
}

