import React, { useState, useEffect } from 'react';
import './ExamSession.css';

const ExamSession = ({ exam, onClose }) => {
    const [timeLeft, setTimeLeft] = useState(exam.time_allowed_minutes * 60 || 3600);
    const [answers, setAnswers] = useState({});
    const [flagged, setFlagged] = useState({});
    const [sections, setSections] = useState([]);
    const [loading, setLoading] = useState(true);

    const [examMeta, setExamMeta] = useState({ name: exam.course_name, code: exam.course_code });

    useEffect(() => {
        console.log("[SESSION] Fetching real questions from DB...");
        fetch('https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'get_exam_questions', exam_id: exam.id })
        })
        .then(res => res.json())
        .then(data => {
            if (data.sections) {
                setSections(data.sections);
                // Standardize title from joined data
                setExamMeta({ name: data.course_name, code: data.course_code });
            }
            setLoading(false);
        })
        .catch(err => console.error("[SESSION_ERROR]", err));
    }, [exam.id]);

    useEffect(() => {
        const timer = setInterval(() => {
            setTimeLeft(prev => prev > 0 ? prev - 1 : 0);
        }, 1000);
        return () => clearInterval(timer);
    }, []);

    const formatTime = (seconds) => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const handleSelect = (qId, opt) => {
        setAnswers(prev => ({ ...prev, [qId]: opt }));
    };

    const toggleFlag = (qId) => {
        setFlagged(prev => ({ ...prev, [qId]: !prev[qId] }));
    };

    const scrollToQuestion = (id) => {
        const el = document.getElementById(`q-box-${id}`);
        if (el) {
            el.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    };

    const allQuestions = sections.flatMap(s => s.questions);
    const totalCount = allQuestions.length || 1;
    const progress = (Object.keys(answers).length / totalCount) * 100;
    const flaggedCount = Object.values(flagged).filter(Boolean).length;
    const flaggedProgress = (flaggedCount / totalCount) * 100;

    return (
        <div className="exam-session-overlay">
            <header className="session-header">
                <div className="session-title-box">
                    <p>{examMeta.code}</p>
                    <h1>{examMeta.name}</h1>
                </div>
                <div className="session-header-actions">
                    <div className={`timer-pill ${timeLeft < 300 ? 'urgent' : ''}`}>
                        {formatTime(timeLeft)}
                    </div>
                    <button className="icon-button exit-session-btn" onClick={onClose} title="Exit Exam">
                        <i className="fas fa-times"></i>
                    </button>
                </div>
            </header>

            <nav className="question-nav-strip">
                {allQuestions.map((q, i) => (
                    <div 
                        key={q.id} 
                        onClick={() => scrollToQuestion(q.id)}
                        className={`nav-dot ${answers[q.id] ? 'answered' : ''} ${flagged[q.id] ? 'flagged' : ''}`}
                    >
                        {i + 1}
                    </div>
                ))}
            </nav>

            <main className="exam-viewport">
                {loading ? (
                    <div style={{padding: '2rem', textAlign: 'center'}}>Assembling Exam Papers...</div>
                ) : sections.map((section) => (
                    <div key={section.id} className="section-wrap">
                        <div className="section-header-display" style={{padding: '1rem 0', borderBottom: '1px solid rgba(255,255,255,0.1)', marginBottom: '1rem'}}>
                            <h3 style={{color: 'var(--accent-teal)'}}>{section.title}</h3>
                            <p style={{fontSize: '0.8rem', opacity: 0.6}}>{section.instructions}</p>
                        </div>
                        {section.questions.map((q, idx) => (
                    <section className="q-row" key={q.id} id={`q-box-${q.id}`}>
                        <div className="q-meta">
                            <span className="q-label">Question {idx + 1}</span>
                            <div className="q-actions">
                                <button className="hint"><i className="fas fa-wand-magic-sparkles"></i></button>
                                <button 
                                    className={flagged[q.id] ? 'active' : ''} 
                                    onClick={() => toggleFlag(q.id)}
                                >
                                    <i className={flagged[q.id] ? 'fas fa-flag' : 'far fa-flag'}></i>
                                </button>
                            </div>
                        </div>
                        <div className="q-text">{q.text}</div>
                        <div className={`options-cluster ${q.options?.some(o => (o.text || o).length > 45) ? 'vertical-layout' : ''}`}>
                            {q.options?.map((opt, idx) => (
                                <div className="opt-wrapper" key={idx}>
                                    <input 
                                        type="radio" 
                                        name={`q-${q.id}`} 
                                        id={`q-${q.id}-${idx}`} 
                                        hidden 
                                        checked={answers[q.id] === opt}
                                        onChange={() => handleSelect(q.id, opt)}
                                    />
                                    <label htmlFor={`q-${q.id}-${idx}`} className="opt-btn">
                                        <div className="opt-indicator"></div>
                                        <span>{opt.text || opt}</span>
                                    </label>
                                </div>
                            ))}

                            {(q.question_type === 'matching' || q.matching_data) && (
                                <div className="q-matching-container">
                                    <div className="q-match-column q-column-a">
                                        {q.matching_data?.left_column?.map((item, i) => <div key={i} className="q-match-item">{item.text || item}</div>)}
                                    </div>
                                    <div className="q-match-column q-column-b">
                                        {q.matching_data?.right_column?.map((item, i) => <div key={i} className="q-match-item">{item.text || item}</div>)}
                                    </div>
                                </div>
                            )}
                        </div>
                    </section>
                ))}
                </div>
                ))}
            </main>

            <footer className="session-footer">
                <div className="session-progress-block">
                    <div className="p-text">
                        <span>{Object.keys(answers).length} / {totalCount} Answered</span>
                        <span>{Math.round(progress)}% Complete</span>
                    </div>
                    <div className="p-track">
                        <div className="p-bar-fill" style={{ width: `${progress}%` }}></div>
                        <div className="p-bar-flagged" style={{ width: `${flaggedProgress}%`, left: `${progress}%` }}></div>
                    </div>
                </div>
                <button className="finish-exam-btn" onClick={onClose}>Finish Exam</button>
            </footer>
        </div>
    );
};

export default ExamSession;

import React, { useState, useEffect } from 'react';

const Home = ({ onOpenActivity }) => {
    const [greeting, setGreeting] = useState('Hello');
    const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
    const [isFading, setIsFading] = useState(false);

    const tasks = [
        { icon: 'fas fa-users', title: 'Physics Study Group', category: 'Collaboration', dueIn: '5d' },
        { icon: 'fas fa-book-open', title: 'Chapter 5 Reading', category: 'Literature', dueIn: '9d' },
        { icon: 'fas fa-flask', title: 'Lab Report Draft', category: 'Chemistry', dueIn: '12d' }
    ];

    useEffect(() => {
        // Greeting Logic
        const currentHour = new Date().getHours();
        if (currentHour < 12) setGreeting('Good Morning');
        else if (currentHour < 18) setGreeting('Good Afternoon');
        else setGreeting('Good Evening');

        // Task Rotation Logic
        const interval = setInterval(() => {
            setIsFading(true);
            setTimeout(() => {
                setCurrentTaskIndex((prev) => (prev + 1) % tasks.length);
                setIsFading(false);
            }, 400);
        }, 4000);

        return () => clearInterval(interval);
    }, []);

    const currentTask = tasks[currentTaskIndex];

    // Dynamic background based on time
    const getHeroImage = () => {
        const h = new Date().getHours();
        if (h < 12) return 'https://images.unsplash.com/photo-1500382017468-9049fed747ef?auto=format&fit=crop&w=1800&q=80';
        if (h < 18) return 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=crop&w=1800&q=80';
        return 'https://images.unsplash.com/photo-1475924156734-496f6cac6ec1?auto=format&fit=crop&w=1800&q=80';
    };

    return (
        <div className="tab-content active" id="home-content">
            <div className="scrollable-content">
                <div className="hero-wrapper">
<header className="app-header">
                        <div className="welcome-text"><h1>{greeting}, Alex</h1></div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                            <button className="icon-button notification-btn" onClick={onOpenActivity}>
                                <i className="fas fa-bell"></i>
                                <span className="notification-badge">3</span>
                            </button>
                            <img 
                                src="https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?ixlib=rb-4.0.3&auto-format=fit&crop=w=80&q=80" 
                                alt="Profile" 
                                className="profile-avatar" 
                            />
                        </div>
                    </header>
                    <section 
                        className="welcome-hero" 
                        style={{ backgroundImage: `url('${getHeroImage()}')` }}
                    >
                        <div className="overlay"></div>
                        <div className="hero-summary">
                            <h2>You're on track.</h2>
                            <p>3 tasks are due this week.</p>
                        </div>
                    </section>
                </div>

                <div className="page-content">
                    <section className="priority-section">
                        <h2 className="section-label">Urgent</h2>
                        <div className="priority-scroll-wrapper">
                            <div className="priority-track">
                                <a href="#" className="priority-card card-base is-urgent">
                                    <div>
                                        <div className="card-header">
                                            <i className="fas fa-file-signature icon"></i>
                                            <span className="category">Exam</span>
                                        </div>
                                        <h3 className="title">Thermodynamics</h3>
                                    </div>
                                    <div className="countdown is-urgent-text">3<span className="label">days</span></div>
                                </a>
                                <a href="#" className="priority-card card-base">
                                    <div>
                                        <div className="card-header">
                                            <i className="fas fa-clipboard-list icon"></i>
                                            <span className="category">Assignment</span>
                                        </div>
                                        <h3 className="title">Problem Set 5 Due</h3>
                                    </div>
                                    <div className="countdown">7<span className="label">days</span></div>
                                </a>
                            </div>
                        </div>
                    </section>

                    <section className="whats-next-section">
                        <h2 className="section-label">What's Next</h2>
                        <div className="next-task-container card-base">
                            <div id="next-task-content" className={isFading ? 'is-fading' : ''}>
                                <div className="task-icon"><i className={currentTask.icon}></i></div>
                                <div className="task-details">
                                    <div className="title">{currentTask.title}</div>
                                    <div className="category">{currentTask.category}</div>
                                </div>
                                <div className="task-countdown">{currentTask.dueIn}</div>
                            </div>
                        </div>
                    </section>
                </div>
            </div>
        </div>
    );
};

export default Home;

