                const duration = 2000;
                const stepTime = 20;
                const steps = duration / stepTime;
                const increment = target / steps;
                const timer = setInterval(() => {
                    start += increment;
                    if (start >= target) {
                        setVal(target);
                        clearInterval(timer);
                    } else {
                        setVal(Math.floor(start));
                    }
                }, stepTime);
                return () => clearInterval(timer);
            } else {
                setVal(0);
            }
        }, [overlays.observatory, target]);
        return <span>{val}</span>;
    };

    return (
