/* --- GENERAL OVERLAY STYLES --- */
/* (Updated for desktop compatibility in media query below, but keeping mobile base here) */
.fullscreen-overlay { position: fixed; inset: 0; z-index: 1000; background-color: var(--bg-dark); opacity: 0; pointer-events: none; clip-path: circle(5% at 50% 50%); transition: opacity 0.5s ease, clip-path 0.6s cubic-bezier(0.76, 0, 0.24, 1); }
.fullscreen-overlay.is-active { opacity: 1; pointer-events: auto; clip-path: circle(120% at 50% 50%); }
