.next-steps-card { background: linear-gradient(45deg, rgba(155, 89, 182, 0.1), rgba(66, 215, 184, 0.1)); border-radius: 20px; padding: 1.25rem; display: flex; gap: 1rem; align-items: center; border: 1px solid var(--purple-glow); margin-bottom: 2.5rem; }
.next-steps-icon { font-size: 1.8rem; color: var(--purple-glow); }
