.achievement-label { font-size: 0.7rem; color: var(--text-secondary-dark); text-align: center; }

/* --- MISSION CONTROL (TASKS) OVERLAY STYLES --- */
.tasks-nav { display: flex; position: relative; border-bottom: 1px solid var(--border-color); }
.nav-tab { flex: 1; padding: 0.75rem; text-align: center; font-weight: 500; color: var(--text-secondary-dark); cursor: pointer; }
.nav-tab.active { color: var(--text-primary-dark); }
