async function bundleAndPreview(index) {
    if(!CONFIG.funcUrl) return;
    // Clear temporary runtime logs on every new build
    document.querySelectorAll('.runtime-log').forEach(el => el.remove());

    console.group("🧬 WASM BUNDLER SCAN");

    let entry = (typeof index === 'number') ? dbHistory[index] : null;
    let sha = entry ? entry.sha : null;
    let rootPrefix = ''; 
