                    const res = Babel.transform(fileCache[path].content, { presets: [['env', { modules: false }], 'react'], filename: path });
                    fileCache[path].content = res.code;
                    fileCache[path].mime = 'text/javascript'; 
                    window.BUILD_CACHE[cacheKey] = { sha: currentSha, code: res.code };
                } catch (e) {
                    return iframe.srcdoc = `<div style="color:red; font-family:monospace; padding:20px;"><strong>Build Error in ${path}:</strong><br>${e.message}</div>`;
                }
            }
        }

        if (fileCache[path].mime === 'text/css') {
             const cleanCss = fileCache[path].content.replace(/`/g, '\\`').replace(/\\/g, '\\\\');
             fileCache[path].content = `const style = document.createElement('style'); style.textContent = \`${cleanCss}\`; document.head.appendChild(style);`;
             fileCache[path].mime = 'text/javascript';
        }
        if (fileCache[path].mime === 'application/json') {
            fileCache[path].content = `export default ${fileCache[path].content};`;
            fileCache[path].mime = 'text/javascript';
        }
        if (fileCache[path].mime === 'image') {
            const ext = path.split('.').pop();
            let imgMime = 'image/png';
            if(ext === 'svg') imgMime = 'image/svg+xml';
            const dataUri = `data:${imgMime};base64,${fileCache[path].content}`;
            fileCache[path].content = `export default "${dataUri}";`;
            fileCache[path].mime = 'text/javascript';
        }

        const blob = new Blob([fileCache[path].content], { type: fileCache[path].mime });
        fileCache[path].blobUrl = URL.createObjectURL(blob);
        importMap.imports[mapKey] = fileCache[path].blobUrl;
    });

    let html = fileCache[entryFile].content;
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');

    const flagScript = doc.createElement('script');
    flagScript.textContent = 'window.IS_CONDUIT_PREVIEW = true; window.process = { env: { NODE_ENV: "development" } };' + 
        '\n\n// --- PREVIEW CONSOLE SYNC ---\n' + 
        'const sendToConduit = (type, args) => { ' + 
        '  window.parent.postMessage({ type: "CONDUIT_CONSOLE", method: type, msg: Array.from(args).map(a => typeof a === "object" ? JSON.stringify(a) : String(a)).join(" ") }, "*"); ' + 
        '};\n' + 
        'const originalLog = console.log; const originalError = console.error;\n' + 
        'console.log = function() { sendToConduit("log", arguments); originalLog.apply(console, arguments); };\n' + 
        'console.error = function() { sendToConduit("error", arguments); originalError.apply(console, arguments); };\n' + 
        'console.warn = function() { sendToConduit("warn", arguments); };\n' + 
        'window.onerror = function(msg, url, line, col, error) { ' + 
        '  sendToConduit("error", ["RUNTIME ERROR: " + msg + " at " + line + ":" + col]); ' + 
        '};';
    doc.head.insertBefore(flagScript, doc.head.firstChild);

    const babelScript = doc.createElement('script');
    babelScript.src = "https://unpkg.com/@babel/standalone/babel.min.js";
    doc.head.appendChild(babelScript);

    doc.querySelectorAll('script[src]').forEach(el => {
        const src = el.getAttribute('src');
        if(!src) return;
        const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);
        if(fileCache[repoPath]) {
            if(fileCache[repoPath].mime === 'text/jsx') {
                const inlineScript = doc.createElement('script');
                inlineScript.type = 'text/babel';
                inlineScript.setAttribute('data-presets', 'react,env');
                inlineScript.textContent = fileCache[repoPath].content;
                el.replaceWith(inlineScript);
            } else if(fileCache[repoPath].mime === 'text/javascript') {
                const cleanKey = repoPath.startsWith(effectiveRoot) ? repoPath.substring(effectiveRoot.length) : repoPath;
                const inlineScript = doc.createElement('script');
                inlineScript.type = 'module';
                inlineScript.textContent = `import "${cleanKey}";`;
                el.replaceWith(inlineScript);
            } else {
                el.src = fileCache[repoPath].blobUrl;
            }
        }
    });

    const mapTag = doc.createElement('script');
    mapTag.type = "importmap";
    mapTag.textContent = JSON.stringify(importMap);
    doc.head.insertBefore(mapTag, doc.head.firstChild);

    const finalHtml = doc.documentElement.outerHTML;
    iframe.srcdoc = finalHtml;

    if(window.PREVIEW_BLOB_URL) URL.revokeObjectURL(window.PREVIEW_BLOB_URL);
    const blob = new Blob([finalHtml], { type: 'text/html' });
    window.PREVIEW_BLOB_URL = URL.createObjectURL(blob);
    if(window.POPOUT_REF && !window.POPOUT_REF.closed) window.POPOUT_REF.location.replace(window.PREVIEW_BLOB_URL);
    document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;
}

