        for (const fullPath in fileCache) {
            const file = fileCache[fullPath];
            const virtualPath = fullPath.substring(effectiveRoot.length);
            const isJs = ['js', 'mjs', 'ts', 'jsx', 'tsx'].includes(file.ext);

            if (isJs) {
                file.content = file.content.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
                    if (importPath.startsWith('http') || importPath === 'react' || importPath.startsWith('react-dom')) return match;
                    if (importPath.startsWith('.')) {
                        const resolvedFull = resolvePath(fullPath, importPath);
                        if (resolvedFull.startsWith(effectiveRoot)) return `${keyword}${mid}${q1}${resolvedFull.substring(effectiveRoot.length)}${q2}`;
                    }
                    return match;
                });

                if (['jsx', 'tsx'].includes(file.ext)) {
                    try {
                        const res = Babel.transform(file.content, { presets: [['env', { modules: false }], 'react'], filename: fullPath });
                        file.content = res.code;
                    } catch (e) { throw new Error(`Babel Error in ${fullPath}: ${e.message}`); }
                }
            }

            if (file.ext === 'css') {
                const cleanCss = file.content.replace(/`/g, '\\`').replace(/\\/g, '\\\\');
                file.content = `const s = document.createElement('style'); s.textContent = \`${cleanCss}\`; document.head.appendChild(s);`;
                file.ext = 'js';
            }

            const mime = file.ext === 'js' ? 'text/javascript' : (file.ext === 'html' ? 'text/html' : 'application/octet-stream');
            const blob = new Blob([file.content], { type: mime });
            file.blobUrl = URL.createObjectURL(blob);
            importMap.imports[virtualPath] = file.blobUrl;
            importMap.imports['./' + virtualPath] = file.blobUrl;
        }

        const doc = new DOMParser().parseFromString(fileCache[entryFile].content, 'text/html');
        const baseScript = doc.createElement('script');
        baseScript.textContent = 'window.IS_CONDUIT_PREVIEW = true; window.process = { env: { NODE_ENV: "development" } };';
        doc.head.prepend(baseScript);

        doc.querySelectorAll('script[src]').forEach(el => {
            const src = el.getAttribute('src');
            if (src && !src.startsWith('http')) {
                const resolved = resolvePath(entryFile, src);
                if (fileCache[resolved]) {
                    const inline = doc.createElement('script');
                    inline.type = 'module';
                    inline.textContent = `import "${resolved.substring(effectiveRoot.length)}";`;
                    el.replaceWith(inline);
                }
            }
        });

        const mapTag = doc.createElement('script');
        mapTag.type = "importmap";
        mapTag.textContent = JSON.stringify(importMap);
        doc.head.prepend(mapTag);

        iframe.srcdoc = doc.documentElement.outerHTML;
        if(window.PREVIEW_BLOB_URL) URL.revokeObjectURL(window.PREVIEW_BLOB_URL);
        window.PREVIEW_BLOB_URL = URL.createObjectURL(new Blob([iframe.srcdoc], { type: 'text/html' }));
        if(window.POPOUT_REF && !window.POPOUT_REF.closed) window.POPOUT_REF.location.replace(window.PREVIEW_BLOB_URL);
        document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;

    } catch(e) { iframe.srcdoc = `<div style="color:red; padding:20px;"><b>Preview Error:</b><br>${e.message}</div>`; }
}

