            const dataUri = `data:${imgMime};base64,${fileCache[path].content}`;
            fileCache[path].content = `export default "${dataUri}";`;
            fileCache[path].mime = 'text/javascript';
        }

        const blob = new Blob([fileCache[path].content], { type: fileCache[path].mime });
        fileCache[path].blobUrl = URL.createObjectURL(blob);
        importMap.imports[mapKey] = fileCache[path].blobUrl;
    });

    let html = fileCache[entryFile].content;
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');

    const flagScript = doc.createElement('script');
    flagScript.textContent = 'window.IS_CONDUIT_PREVIEW = true; window.process = { env: { NODE_ENV: "development" } };' + 
        '\n\n// --- PREVIEW CONSOLE SYNC ---\n' + 
        'const sendToConduit = (type, args) => { ' + 
        '  window.parent.postMessage({ type: "CONDUIT_CONSOLE", method: type, msg: Array.from(args).map(a => typeof a === "object" ? JSON.stringify(a) : String(a)).join(" ") }, "*"); ' + 
        '};\n' + 
        'const originalLog = console.log; const originalError = console.error;\n' + 
        'console.log = function() { sendToConduit("log", arguments); originalLog.apply(console, arguments); };\n' + 
        'console.error = function() { sendToConduit("error", arguments); originalError.apply(console, arguments); };\n' + 
        'console.warn = function() { sendToConduit("warn", arguments); };\n' + 
        'window.onerror = function(msg, url, line, col, error) { ' + 
        '  sendToConduit("error", ["RUNTIME ERROR: " + msg + " at " + line + ":" + col]); ' + 
        '};';
    doc.head.insertBefore(flagScript, doc.head.firstChild);

    const babelScript = doc.createElement('script');
    babelScript.src = "https://unpkg.com/@babel/standalone/babel.min.js";
    doc.head.appendChild(babelScript);

    doc.querySelectorAll('script[src]').forEach(el => {
        const src = el.getAttribute('src');
        if(!src) return;
        const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);
        if(fileCache[repoPath]) {
            if(fileCache[repoPath].mime === 'text/jsx') {
                const inlineScript = doc.createElement('script');
                inlineScript.type = 'text/babel';
                inlineScript.setAttribute('data-presets', 'react,env');
                inlineScript.textContent = fileCache[repoPath].content;
                el.replaceWith(inlineScript);
            } else if(fileCache[repoPath].mime === 'text/javascript') {
                const cleanKey = repoPath.startsWith(effectiveRoot) ? repoPath.substring(effectiveRoot.length) : repoPath;
                const inlineScript = doc.createElement('script');
                inlineScript.type = 'module';
                inlineScript.textContent = `import "${cleanKey}";`;
                el.replaceWith(inlineScript);
            } else {
                el.src = fileCache[repoPath].blobUrl;
            }
        }
    });

    const mapTag = doc.createElement('script');
    mapTag.type = "importmap";
    mapTag.textContent = JSON.stringify(importMap);
    doc.head.insertBefore(mapTag, doc.head.firstChild);

    const finalHtml = doc.documentElement.outerHTML;
    iframe.srcdoc = finalHtml;

    if(window.PREVIEW_BLOB_URL) URL.revokeObjectURL(window.PREVIEW_BLOB_URL);
    const blob = new Blob([finalHtml], { type: 'text/html' });
    window.PREVIEW_BLOB_URL = URL.createObjectURL(blob);
    if(window.POPOUT_REF && !window.POPOUT_REF.closed) window.POPOUT_REF.location.replace(window.PREVIEW_BLOB_URL);
    document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;
}

operations.replace_with:
async function bundleAndPreview(index) {
    if(!CONFIG.funcUrl) return;
    document.querySelectorAll('.runtime-log').forEach(el => el.remove());

    let entry = (typeof index === 'number') ? dbHistory[index] : null;
    let sha = entry ? entry.sha : null;
    let rootPrefix = ''; 
    if (entry && entry.type === 'Prod') {
        const match = entry.title.match(/Deployed\s+(.+)/);
        if (match && match[1]) rootPrefix = match[1];
    }

    let effectiveRoot = (rootPrefix || CONFIG.projectPath || "").replace(/^\/+/, "");
    if (effectiveRoot && !effectiveRoot.endsWith('/')) effectiveRoot += '/';

    const entryFile = effectiveRoot + 'index.html';
    const iframe = document.getElementById('preview-frame');
    iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Initializing Environment...</div>`;

    const fileCache = {}; window.CURRENT_FILE_CACHE = fileCache;

    try {
        const treeRes = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'fetch_tree', project_path: effectiveRoot, ref_sha: sha })
        });
        const treeData = await treeRes.json();
        const files = (treeData.files || []).filter(f => f.path.startsWith(effectiveRoot));

        if (files.length === 0) throw new Error(`No files found in scope: ${effectiveRoot}`);
        console.log("📦 [Bundler] Files in Scope:", files.map(f => f.path));

        const BATCH_SIZE = 12;
        for (let i = 0; i < files.length; i += BATCH_SIZE) {
            const batch = files.slice(i, i + BATCH_SIZE);
            iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Fetching Module: ${i}/${files.length}...</div>`;
            await Promise.all(batch.map(async (file) => {
                try {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'preview_file', file_path: file.path, ref_sha: sha })
                    });
                    const data = await res.json();
                    if (data.content) {
                        const ext = file.path.split('.').pop().toLowerCase();
                        fileCache[file.path] = { 
                            content: (['png', 'jpg', 'jpeg', 'gif', 'svg', 'ico'].includes(ext)) ? data.content : b64DecodeUnicode(data.content),
                            ext, sha: file.sha 
                        };
                    }
                } catch(e) { console.error("Fetch fail", file.path); }
            }));
        }

        if(!fileCache[entryFile]) throw new Error(`Entry file ${entryFile} not found.`);

        const importMap = { imports: { "react": "https://esm.sh/react@18.2.0", "react-dom/client": "https://esm.sh/react-dom@18.2.0/client" } };

        for (const fullPath in fileCache) {
            const file = fileCache[fullPath];
            const virtualPath = fullPath.substring(effectiveRoot.length);
            const isJs = ['js', 'mjs', 'ts', 'jsx', 'tsx'].includes(file.ext);

            if (isJs) {
                file.content = file.content.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
                    if (importPath.startsWith('http') || importPath === 'react' || importPath.startsWith('react-dom')) return match;
                    if (importPath.startsWith('.')) {
                        const resolvedFull = resolvePath(fullPath, importPath);
                        if (resolvedFull.startsWith(effectiveRoot)) return `${keyword}${mid}${q1}${resolvedFull.substring(effectiveRoot.length)}${q2}`;
                    }
                    return match;
                });

                if (['jsx', 'tsx'].includes(file.ext)) {
                    try {
                        const res = Babel.transform(file.content, { presets: [['env', { modules: false }], 'react'], filename: fullPath });
                        file.content = res.code;
                    } catch (e) { throw new Error(`Babel Error in ${fullPath}: ${e.message}`); }
                }
            }

            if (file.ext === 'css') {
                const cleanCss = file.content.replace(/`/g, '\\`').replace(/\\/g, '\\\\');
                file.content = `const s = document.createElement('style'); s.textContent = \`${cleanCss}\`; document.head.appendChild(s);`;
                file.ext = 'js';
            }

            const mime = file.ext === 'js' ? 'text/javascript' : (file.ext === 'html' ? 'text/html' : 'application/octet-stream');
            const blob = new Blob([file.content], { type: mime });
            file.blobUrl = URL.createObjectURL(blob);
            importMap.imports[virtualPath] = file.blobUrl;
            importMap.imports['./' + virtualPath] = file.blobUrl;
        }

        const doc = new DOMParser().parseFromString(fileCache[entryFile].content, 'text/html');
        const baseScript = doc.createElement('script');
        baseScript.textContent = 'window.IS_CONDUIT_PREVIEW = true; window.process = { env: { NODE_ENV: "development" } };';
        doc.head.prepend(baseScript);

        doc.querySelectorAll('script[src]').forEach(el => {
            const src = el.getAttribute('src');
            if (src && !src.startsWith('http')) {
                const resolved = resolvePath(entryFile, src);
                if (fileCache[resolved]) {
                    const inline = doc.createElement('script');
                    inline.type = 'module';
                    inline.textContent = `import "${resolved.substring(effectiveRoot.length)}";`;
                    el.replaceWith(inline);
                }
            }
        });

        const mapTag = doc.createElement('script');
        mapTag.type = "importmap";
        mapTag.textContent = JSON.stringify(importMap);
        doc.head.prepend(mapTag);

        iframe.srcdoc = doc.documentElement.outerHTML;
        if(window.PREVIEW_BLOB_URL) URL.revokeObjectURL(window.PREVIEW_BLOB_URL);
        window.PREVIEW_BLOB_URL = URL.createObjectURL(new Blob([iframe.srcdoc], { type: 'text/html' }));
        if(window.POPOUT_REF && !window.POPOUT_REF.closed) window.POPOUT_REF.location.replace(window.PREVIEW_BLOB_URL);
        document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;

    } catch(e) { iframe.srcdoc = `<div style="color:red; padding:20px;"><b>Preview Error:</b><br>${e.message}</div>`; }
}

