async function deployEdgeFunction() {
    console.group("🚀 Edge Function Deployment");
    const name = document.getElementById('ef-name').value.trim();
    let code = document.getElementById('ef-code').value.trim();
    const status = document.getElementById('ef-status-msg');

    console.log("Target Function:", name);
    if (!name) return alert("Enter a function name.");

    // Save preference
    localStorage.setItem('conduit_last_ef', name);

    // 1. AUTO-FETCH if editor is empty/stale
    let isFreshCode = true;
    const isDefaultTemplate = code.startsWith("import { serve");

    if (!code || code === "Loading..." || isDefaultTemplate) {
         status.innerText = "📥 Checking existing source...";
         try {
            const res = await fetch(CONFIG.funcUrl, { 
                method: 'POST', 
                headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'preview_file', file_path: `supabase/functions/${name}/index.ts` }) 
            });
            const data = await res.json();

            if (data.content) {
                // File exists on GitHub, sync it to ensure validation is accurate
                code = b64DecodeUnicode(data.content);
                isFreshCode = false; 
            } else {
                // File doesn't exist, but we have boilerplate. This is a NEW function.
                if (isDefaultTemplate) {
                    console.log("Detected new function creation from template.");
                    status.innerText = "🆕 Preparing new function...";
                    isFreshCode = true;
                } else {
                    throw new Error("Source not found.");
                }
            }
         } catch (e) {
            // Handle total failure (like 404 or network error)
            if (isDefaultTemplate) {
                console.log("File not found on GitHub, proceeding as new creation.");
                isFreshCode = true;
            } else {
                return alert(`Cannot deploy: Could not verify '${name}'. ` + e.message);
            }
         }
    }

